python - <<'PY'
import json, glob, os
from pathlib import Path

entries=[]
for p in sorted(Path('day12').glob('*.json')):
    data=json.load(open(p))
    # identify report vs raw
    report_type=None
    created_at=None
    if isinstance(data, dict) and 'meta' in data and isinstance(data['meta'], dict):
        created_at=data['meta'].get('created_at')
        content=data.get('content')
        if isinstance(content, dict):
            report_type=content.get('report_type')
    else:
        # raw files
        if p.name=='monthly_api_stats_raw.json':
            report_type='raw_api_stats'
        elif p.name=='user_sessions_raw.json':
            report_type='raw_user_sessions'
        else:
            report_type='raw_or_legacy'
    entries.append({
        'filename': p.name,
        'type': report_type,
        'generated_at': created_at
    })

index={
  'meta': {
    'created_at': '2026-03-31T09:10:00+08:00',
    'author': 'metaclaw_agent',
    'status': 'done'
  },
  'content': {
    'report_type': 'day12_report_index',
    'directory': 'day12',
    'entries': entries,
    'notes': [
        'generated_at is taken from meta.created_at when present; raw/legacy files have null generated_at.',
        'This index includes all JSON files in day12/, including raw inputs.'
    ]
  }
}

out='day12/20260331_day12_report_index.json'
open(out,'w').write(json.dumps(index, indent=2)+"\n")
print(out)
PY

